containers/db-first-response-lab:
cat > /usr/local/bin/df <<'SH'
#!/usr/bin/env bash
case "$*" in
  *postgresql*) printf 'Filesystem      Size  Used Avail Use%% Mounted on\n/dev/vda1        40G   27G   11G  72%% /var/lib/postgresql\n' ;;
  *mysql*) printf 'Filesystem      Size  Used Avail Use%% Mounted on\n/dev/vdb1        80G   59G   17G  78%% /var/lib/mysql\n' ;;
  *) /bin/df "$@" ;;
esac
SH
chmod +x /usr/local/bin/df

cat > /usr/local/bin/pg_isready <<'SH'
#!/usr/bin/env bash
